&lt;p&gt;अतः स्पष्ट है कि&amp;nbsp;उकारान्त पुल्लिङ्ग शब्द &amp;lsquo;मनु&amp;rsquo; का प्रथमा बहुवचन में रूप बनता है&lt;span style=&quot;font-weight: 700;&quot;&gt;- &amp;lsquo;&lt;/span&gt;&lt;u style=&quot;text-align: -webkit-center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;मनवः&lt;/span&gt;&lt;/u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;rsquo;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;किसी वाक्य के वाच्य से ज्ञात होता&amp;nbsp;है कि&amp;nbsp;वाक्य में&amp;nbsp;कर्ता, कर्म या भाव प्रधान है। संस्कृत में तीन वाच्य होते हैं-&lt;/p&gt;

&lt;p&gt;१. कर्तृवाच्य २. कर्मवाच्य ३. भाववाच्य&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 75px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नाम&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 159.467px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;परिभाषा&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 119px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 75px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कर्तृवाच्य&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 360px;&quot;&gt;
			&lt;p&gt;क्रिया अकर्मक, सकर्मक दोनों होती है और क्रिया द्वारा कर्ता उक्त होता है। कर्ता में प्रथमा विभक्ति तथा कर्म में द्वितिया विभक्ति होती है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 119px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;सः गृहं गच्छति।&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;मयूराः नृत्यन्ति।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 75px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कर्मवाच्य&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 360px;&quot;&gt;
			&lt;p&gt;क्रिया सकर्मक होती है और क्रिया द्वारा कर्म उक्त होता है। यहाँ कर्ता में तृतीया और कर्म प्रथमा विभक्ति में होती है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 119px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;तेन विद्यालयः गम्यते।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 75px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;भाववाच्य&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 360px;&quot;&gt;
			&lt;p&gt;अकर्मक क्रिया होती है और क्रिया द्वारा भाव उक्त होता है। यहाँ कर्ता में तृतीया विभक्ति होती है और कर्म नहीं होता।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 119px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;मया हस्यते।&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;मयूरैः नृत्यते।&lt;/p&gt;
			&lt;/td&gt;
