&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;इससे यह स्पष्ट होता है कि&amp;nbsp;&lt;strong&gt;&amp;#39;रामः वार्तां करोति&amp;#39; &lt;/strong&gt;इस वाक्य का वाच्यपरिवर्तन&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;रामेण वार्ता&amp;nbsp;क्रियते।&amp;rsquo;&lt;/span&gt;&amp;nbsp;होगा।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;पद -&lt;/strong&gt;&amp;nbsp;&lt;span style=&quot;text-align: center;&quot;&gt;तट्टिका&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;सन्धि विच्छेद -&lt;/strong&gt;&amp;nbsp;तत् + टिका&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नियम:-&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;स्&amp;rsquo; या &amp;lsquo;तवर्ग&lt;/span&gt;&amp;rsquo; से पूर्व या पश्चाद्&amp;nbsp;&lt;strong&gt;&amp;lsquo;ष्&amp;rsquo;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; या &amp;lsquo;टवर्ग&amp;rsquo;&lt;/span&gt;&amp;nbsp;आये तो क्रमशः परिवर्तन हो जाता है-&lt;/p&gt;

&lt;ul style=&quot;margin-left: 40px;&quot;&gt;
	&lt;li&gt;&amp;lsquo;स्&amp;rsquo; को &amp;lsquo;ष्&amp;rsquo;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&amp;lsquo;त्&amp;rsquo; को &amp;lsquo;ट्&amp;rsquo;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;थ्&amp;rsquo; को &amp;lsquo;ठ्&amp;rsquo;&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;द्&amp;rsquo; को &amp;lsquo;ड्&amp;rsquo;&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;ध्&amp;rsquo; को &amp;lsquo;ढ्&amp;rsquo;&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;न्&amp;rsquo; को &amp;lsquo;ण्&amp;rsquo;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सूत्र:-&amp;nbsp;&lt;/span&gt;&amp;lsquo;ष्टुना ष्टुः&amp;rsquo;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण:-&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;text-align: center;&quot;&gt;हरिस् + टिकटे&lt;/span&gt; = &lt;span style=&quot;text-align: center;&quot;&gt;हरिष्टीकते&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;text-align: center;&quot;&gt;तत् + टिका&lt;/span&gt; = &lt;span style=&quot;text-align: center;&quot;&gt;तट्टिका&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;षट् + नाम्&amp;nbsp;=&amp;nbsp;षण्णाम्&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;span style=&quot;text-align: center;&quot;&gt;तट्टिका&amp;#39;&lt;/span&gt; &lt;/span&gt;&lt;strong&gt;ष्टुत्व&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt; सन्धि&amp;nbsp;&lt;/span&gt;का उदाहरण है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि-&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;दो शब्दों के संयोग से होने वाले परिवर्तन को सन्धि कहते हैं। जैसे-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;विद्या + आलय = विद्यालय।&lt;/li&gt;
	&lt;li&gt;रमा + ईश = रमेश&lt;/li&gt;
	&lt;li&gt;न + एकः = नैकः&lt;/li&gt;
	&lt;li&gt;सम्यक् + ज्ञानम् = सम्यग्ज्ञानम्&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि के प्रकार-&amp;nbsp;&lt;/span&gt;सन्धि के तीन प्रकार होते हैं -&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;background-color: rgb(255, 255, 255); width: 370px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सन्धि&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;परिभाषा&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 151px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 21px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;स्वरसन्धि&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 21px;&quot;&gt;
			&lt;p&gt;स्वर वर्ण&amp;nbsp; का संयोग स्वर वर्ण से होने पर जो विकार उत्पन्न होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 151px; height: 21px;&quot;&gt;
			&lt;p&gt;विद्या + आलय = विद्यालय&lt;/p&gt;

			&lt;p&gt;महा + औषधि =&amp;nbsp; महौषधि&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;व्यंजनसन्धि&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 20px;&quot;&gt;
			&lt;p&gt;व्यंजन वर्ण का संयोग व्यंजन या स्वर वर्ण से होने पर जो विकार उत्पन्न होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 151px; height: 20px;&quot;&gt;
			&lt;p&gt;उत् + लास = उल्लास&lt;/p&gt;

			&lt;p&gt;तत् + लय = तल्लयः&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 80px; height: 20px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;विसर्गसन्धि&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 236px; height: 20px;&quot;&gt;
			&lt;p&gt;विसर्ग का सन्योग स्वर या व्यंजन वर्ण से होने पर जो विकार उत्पन्न होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 151px; height: 20px;&quot;&gt;
			&lt;p&gt;दुः + आत्मा = दुरात्मा&lt;/p&gt;

			&lt;p&gt;मनः + रथः = मनोरथः&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;lsquo;कर्मकुशलः&amp;rsquo; पद का समासविग्रह होता है- &amp;lsquo;कर्मणि कुशलः&amp;rsquo; जिससे स्पष्ट होता है कि कुशल के उत्तरपद में होने के कारण यहाँ सप्तमी तत्पुरुष समास है।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;समसनं समासम्&amp;rsquo;&amp;nbsp;&lt;/span&gt;संक्षिप्त करना ही समास होता है अर्थात् दो या दो से अधिक पदों के विभक्ति, समुच्चय बोधक च आदि को संक्षेप करके एक पद बनाने को समास कहते है- &amp;lsquo;अनेकाषां पदानां एकपदी भवनं समासः।&amp;rsquo; इसमें पूर्व और उत्तर दो पद होते हैं। यथा-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पित्रा युक्तः = पितृयुक्तः&lt;/li&gt;
	&lt;li&gt;यूपाय दारु = यूपदारु&lt;/li&gt;
	&lt;li&gt;माता च पिता च = पितरौ&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;समास भेद:- प्रायः समास के पाँच प्रकार बताये गए हैं-&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(1) केवलसमास:&lt;/span&gt;-&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;lsquo;विशेषसंज्ञाविनिर्मुक्तः केवल समासः&amp;rsquo;&lt;/span&gt;&amp;nbsp;अर्थात् विशेष संज्ञा रहित जहाँ केवल समास हो। जैसे:-&amp;nbsp;पूर्वं भूतः = भूतपूर्वः&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(2) अव्ययीभाव:-&amp;nbsp;&lt;/span&gt;&amp;lsquo;प्रायेण पूर्वपदार्थप्रधानोऽव्ययीभावो&amp;rsquo; अर्थात् जहाँ पूर्व पद प्रधान हो तथा अव्यय हो। जैसे:-&amp;nbsp;मतिम् अनतिक्रम्य = यथामति&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(3) तत्पुरुष:- &amp;lsquo;उत्तरपदार्थप्रधानस्तत्पुरुषः&amp;rsquo;&lt;/span&gt;&amp;nbsp;अर्थात् जहाँ उत्तरपद प्रधान हो दोनों पद में अलग-अलग और कभी-कभी समान विभक्ति होती है तथा पूर्वपद के विभक्ति का लोप होता है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;तत्पुरुष समास के भेद:-&amp;nbsp;&lt;/span&gt;इसके दो भेद होते हैं-&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;A) व्याधिकरण तत्पुरुष:-&amp;nbsp;&lt;/span&gt;इसके सात प्रकार होते हैं-&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;द्वितीया तत्पुरुष:&lt;/span&gt;- श्रित, अतीत, आगतादि शब्द यदि उत्तरपद हो तो द्वितीया तत्पुरुष समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;कृष्णं श्रितः = कृष्णश्रित&lt;/li&gt;
	&lt;li&gt;दुःखम् अतीत = दुःखातीत&lt;/li&gt;
	&lt;li&gt;सुखाद् अपेतः = सुखापेतः।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;तृतीया तत्पुरुष:-&amp;nbsp;&lt;/span&gt;हीन, विद्ध आदि शब्द यदि उत्तरपद हो तो तृतीया तत्पुरुष समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सर्पेण दष्टः = सर्पदष्टः&lt;/li&gt;
	&lt;li&gt;शरेण विद्धः = शरविद्धः&lt;/li&gt;
	&lt;li&gt;विद्यया हीनः = विद्याहीनः।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;चतुर्थी तत्पुरुष:-&amp;nbsp;&lt;/span&gt;बलि, अर्थ, तदर्थ आदि शब्द यदि उत्तरपद हो तो चतुर्थी तत्पुरुष समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भूताय बलिः = भूतबलिः&lt;/li&gt;
	&lt;li&gt;स्नानाय इदम् = स्नानार्थम्&lt;/li&gt;
	&lt;li&gt;तस्मै इदम् = तदर्थम्।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पञ्चमी तत्पुरुष:-&amp;nbsp;&lt;/span&gt;भय, मुक्त, पतित आदि शब्द यदि उत्तरपद हो तो पञ्चमी तत्पुरुष समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;चौरद् भयम् = चौरभयम्&lt;/li&gt;
	&lt;li&gt;रोगात् मुक्तः = रोगमुक्तः&lt;/li&gt;
	&lt;li&gt;स्वर्गात् पतितः = स्वर्गपतितः&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;षष्ठी तत्पुरुष:-&amp;nbsp;&lt;/span&gt;जब समस्त पद में दोनों पद एक दुसरे से सम्बन्धित हो तो षष्ठी तत्पुरुष होता है। जैसे-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;राज्ञः पुरुषः = राजपुरुषः&lt;/li&gt;
	&lt;li&gt;गङ्गायाः जलम् = गङ्गाजलम्&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;सप्तमी तत्पुरुष:-&amp;nbsp;&lt;/span&gt;शौण्ड, चतुर, कुशल आदि शब्द यदि उत्तरपद हो तो सप्तमी तत्पुरुष समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सभायां पण्डितः = सभापण्डितः&lt;/li&gt;
	&lt;li&gt;कर्मणि कुशलः = कर्मकुशलः&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नञ् तत्पुरुष:-&amp;nbsp;&lt;/span&gt;जहाँ पूर्वपद अ, अन् अथवा न हो वहाँ नञ् तत्पुरुष समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;न ज्ञानम् = अज्ञानम्&lt;/li&gt;
	&lt;li&gt;न आदि = अनादि&lt;/li&gt;
	&lt;li&gt;न आस्तिक = अनास्तिक&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;B) समानाधिकरण तत्पुरुष:-&amp;nbsp;&lt;/span&gt;इसके दो भेद होते हैं-&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कर्मधारय:-&amp;nbsp;&lt;/span&gt;विशेषण-विशेष्य तथा उपमानोपमेय पदों का परस्पर समास हो तो कर्मधारय समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नीलम् उत्पलम् = नीलोत्पलम्&lt;/li&gt;
	&lt;li&gt;चन्द्र इव मुखम् = चन्द्रमुखम्&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;द्विगु:-&amp;nbsp;&lt;/span&gt;जब विशेषण संख्यावाची हो तो द्विगु समास होता है। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;त्रयाणां भुवनानां समाहारः = त्रिभुवनम्&lt;/li&gt;
	&lt;li&gt;सप्तानां दिनानां समाहारः = सप्तदिनम्&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(4) द्वन्द्व:- &amp;lsquo;उभयपदार्थप्रधानो द्वन्द्वः&amp;rsquo;&lt;/span&gt;&amp;nbsp;जहाँ दोनों पद प्रधान हो। इसके विग्रह में च जुडता है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;माता च पिता च = पितरौ&lt;/li&gt;
	&lt;li&gt;हरिः च हरः च = हरिहरौ&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;इसके तीन प्रकार हैं-&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;इतरेतर द्वन्द्व&lt;/li&gt;
	&lt;li&gt;एकशेष द्वन्द्व&lt;/li&gt;
	&lt;li&gt;समाहार द्वन्द्व&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;(5) बहुव्रीहि:- &amp;lsquo;अन्यपदार्थप्रधानो बहुव्रीहिः&amp;rsquo;&lt;/span&gt;&amp;nbsp;जहाँ अन्य पद प्रधान हो। जैसे:-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पीतम् अम्बरं यस्य सः = पीताम्बरः (हरिः)&lt;/li&gt;
	&lt;li&gt;लम्बः उदरः यस्य सः = लम्बोदरः (गणेशः)&lt;/li&gt;
&lt;/ul&gt;
